     8|
     9|import SwiftUI
    10|
    11|struct MembersView: View {
    12|    @State private var viewModel = MembersViewModel()
    13|    @State private var selectedMember: MemberRecord?
    14|
    15|    var body: some View {
    16|        NavigationStack {
    17|            Group {
    18|                if viewModel.isLoading && viewModel.members.isEmpty {
    19|                    VStack(spacing: 12) {
    20|                        ProgressView()
    21|                        Text("Loading live registry…")
    22|                            .font(.subheadline)
    23|                            .foregroundStyle(.secondary)
    24|                    }
    25|                    .frame(maxWidth: .infinity, maxHeight: .infinity)
    26|                } else if let error = viewModel.errorMessage, viewModel.members.isEmpty {
    27|                    ContentUnavailableView {
    28|                        Label("Registry Unavailable", systemImage: "wifi.exclamationmark")
    29|                    } description: {
    30|                        Text(error)
    31|                    } actions: {
    32|                        Button("Retry") {
    33|                            Task { await viewModel.load() }
    34|                        }
    35|                        .buttonStyle(.borderedProminent)
    36|                    }
    37|                } else {
    38|                    membersList
    39|                }
    40|            }
    41|            .navigationTitle("Members")
    42|            .background(Color.ivxBackground)
    43|            .toolbarBackground(Color.ivxBackground, for: .navigationBar)
    44|            .searchable(text: $viewModel.searchText, prompt: "Search name, email, phone")
    45|            .refreshable { await viewModel.load() }
    46|            .task { await viewModel.load() }
    47|            .toolbar {
    48|                ToolbarItem(placement: .topBarTrailing) {
    49|                    Menu {
    50|                        Picker("Sort", selection: $viewModel.sortOrder) {
    51|                            ForEach(MembersViewModel.SortOrder.allCases) { order in
    52|                                Text(order.rawValue).tag(order)
    53|                            }
    54|                        }
    55|                        ShareLink(
    56|                            item: viewModel.exportCsv,
    57|                            preview: SharePreview("ivx-members.csv")
    58|                        ) {
    59|                            Label("Export CSV", systemImage: "square.and.arrow.up")
    60|                        }
    61|                    } label: {
    62|                        Image(systemName: "arrow.up.arrow.down.circle")
    63|                            .foregroundStyle(Color.ivxGold)
    64|                    }
    65|                }
    66|            }
    67|            .sheet(item: $selectedMember) { member in
    68|                MemberDetailSheet(member: member)
    69|                    .presentationDetents([.medium, .large])
    70|                    .presentationContentInteraction(.scrolls)
    71|            }
    72|        }
    73|    }
    74|
    75|    private var membersList: some View {
    76|        List {
    77|            Section {
    78|                statsHeader
    79|                    .listRowInsets(EdgeInsets(top: 8, leading: 16, bottom: 8, trailing: 16))
    80|                    .listRowBackground(Color.clear)
    81|            }
    82|
    83|            Section {
    84|                Picker("Type", selection: $viewModel.typeFilter) {
    85|                    ForEach(MembersViewModel.TypeFilter.allCases) { filter in
    86|                        Text(filter.rawValue).tag(filter)
    87|                    }
    88|                }
    89|                .pickerStyle(.segmented)
    90|                .listRowInsets(EdgeInsets(top: 4, leading: 16, bottom: 4, trailing: 16))
    91|                .listRowBackground(Color.clear)
    92|            }
    93|
    94|            Section {
    95|                if viewModel.filteredMembers.isEmpty {
    96|                    Text("No members match the current filter.")
    97|                        .font(.subheadline)
    98|                        .foregroundStyle(Color.ivxTextSecondary)
    99|                        .listRowBackground(Color.ivxCard)
   100|                } else {
   101|                    ForEach(viewModel.filteredMembers) { member in
   102|                        Button {
   103|                            selectedMember = member
   104|                        } label: {
   105|                            MemberRow(member: member)
   106|                        }
   107|                        .buttonStyle(.plain)
   108|                        .listRowBackground(Color.ivxCard)
   109|                        .contextMenu {
   110|                            Button {
   111|                                UIPasteboard.general.string = member.memberId
   112|                            } label: {
   113|                                Label("Copy Member ID", systemImage: "doc.on.doc")
   114|                            }
   115|                            if let email = member.email, !email.isEmpty {
   116|                                Button {
   117|                                    UIPasteboard.general.string = email
   118|                                } label: {
   119|                                    Label("Copy Email", systemImage: "envelope")
   120|                                }
   121|                            }
   122|                        }
   123|                    }
   124|                }
   125|            } header: {
   126|                Text("\(viewModel.filteredMembers.count) shown · source: landing registrations")
   127|            } footer: {
   128|                if let refreshed = viewModel.lastRefreshed {
   129|                    Text("Live from api.ivxholding.com · refreshed \(refreshed.formatted(date: .omitted, time: .standard))")
   130|                }
   131|            }
   132|        }
   133|        .listStyle(.insetGrouped)
   134|        .scrollContentBackground(.hidden)
   135|        .background(Color.ivxBackground)
   136|    }
   137|
   138|    private var statsHeader: some View {
   139|        HStack(spacing: 10) {
   140|            RegistryStat(value: "\(viewModel.total)", label: "Total", icon: "person.3.fill", tint: .ivxGold)
   141|            RegistryStat(value: "\(viewModel.investorCount)", label: "Investors", icon: "chart.line.uptrend.xyaxis", tint: .ivxGreen)
   142|            RegistryStat(value: "\(viewModel.buyerCount)", label: "Buyers", icon: "house.fill", tint: .ivxOrange)
   143|            RegistryStat(value: "\(viewModel.smsVerifiedCount)", label: "SMS ✓", icon: "checkmark.shield.fill", tint: .ivxGreen)
   144|        }
   145|    }
   146|}
   147|
   148|private struct RegistryStat: View {
   149|    let value: String
   150|    let label: String
   151|    let icon: String
   152|    let tint: Color
   153|
   154|    var body: some View {
   155|        VStack(spacing: 4) {
   156|            Image(systemName: icon)
   157|                .font(.caption)
   158|                .foregroundStyle(tint)
   159|            Text(value)
   160|                .font(.headline)
   161|                .fontWeight(.bold)
   162|                .monospacedDigit()
   163|            Text(label)
   164|                .font(.caption2)
   165|                .foregroundStyle(Color.ivxTextSecondary)
   166|        }
   167|        .frame(maxWidth: .infinity)
   168|        .padding(.vertical, 10)
   169|        .background(Color.ivxCard)
   170|        .clipShape(.rect(cornerRadius: 12))
   171|        .overlay(
   172|            RoundedRectangle(cornerRadius: 12)
   173|                .stroke(Color.ivxBorder, lineWidth: 1)
   174|        )
   175|    }
   176|}
   177|
   178|private struct MemberRow: View {
   179|    let member: MemberRecord
   180|
   181|    var body: some View {
   182|        HStack(spacing: 12) {
   183|            ZStack {
   184|                Circle()
   185|                    .fill(typeColor.opacity(0.15))
   186|                    .frame(width: 40, height: 40)
   187|                Text(initials)
   188|                    .font(.footnote)
   189|                    .fontWeight(.semibold)
   190|                    .foregroundStyle(typeColor)
   191|            }
   192|
   193|            VStack(alignment: .leading, spacing: 3) {
   194|                Text(member.displayName)
   195|                    .font(.subheadline)
   196|                    .fontWeight(.semibold)
   197|                    .lineLimit(1)
   198|                if let email = member.email, !email.isEmpty {
   199|                    Text(email)
   200|                        .font(.caption)
   201|                        .foregroundStyle(Color.ivxTextSecondary)
   202|                        .lineLimit(1)
   203|                }
   204|                HStack(spacing: 6) {
   205|                    Text(member.typeLabel)
   206|                        .font(.caption2)
   207|                        .fontWeight(.medium)
   208|                        .padding(.horizontal, 6)
   209|                        .padding(.vertical, 2)
   210|                        .background(typeColor.opacity(0.12))
   211|                        .foregroundStyle(typeColor)
   212|                        .clipShape(.capsule)
   213|                    if member.smsVerified == true {
   214|                        Label("SMS", systemImage: "checkmark.shield.fill")
   215|                            .font(.caption2)
   216|                            .foregroundStyle(Color.ivxGreen)
   217|                            .labelStyle(.titleAndIcon)
   218|                    }
   219|                    if let date = member.createdDate {
   220|                        Text(date.formatted(date: .abbreviated, time: .omitted))
   221|                            .font(.caption2)
   222|                            .foregroundStyle(Color.ivxTextTertiary)
   223|                    }
   224|                }
   225|            }
   226|
   227|            Spacer()
   228|        }
   229|        .padding(.vertical, 2)
   230|    }
   231|
   232|    private var initials: String {
   233|        let parts = member.displayName.split(separator: " ").prefix(2)
   234|        let letters = parts.compactMap { $0.first }.map(String.init).joined()
   235|        return letters.isEmpty ? "?" : letters.uppercased()
   236|    }
   237|
   238|    private var typeColor: Color {
   239|        switch (member.memberType ?? "member").lowercased() {
   240|        case "investor": return .ivxGreen
   241|        case "buyer": return .ivxOrange
   242|        case "owner": return .ivxGold
   243|        case "realtor": return .purple
   244|        default: return .ivxBlue
   245|        }
   246|    }
   247|}
   248|
   249|private struct MemberDetailSheet: View {
   250|    let member: MemberRecord
   251|    @State private var copiedField: String?
   252|
   253|    var body: some View {
   254|        NavigationStack {
   255|            List {
   256|                Section("Identity") {
   257|                    detailRow("Member ID", member.memberId, copyable: true)
   258|                    detailRow("Full Name", member.fullName ?? "—")
   259|                    detailRow("Email", member.email ?? "—", copyable: member.email != nil)
   260|                    detailRow("Phone", member.phone ?? "—")
   261|                    detailRow("Auth User ID", member.authUserId ?? "— (lead only, no login)")
   262|                }
   263|                Section("Classification") {
   264|                    detailRow("Member Type", member.typeLabel)
   265|                    detailRow("Source", member.source ?? "—")
   266|                    detailRow("Source Detail", member.sourceDetail ?? "—")
   267|                }
   268|                Section("Verification") {
   269|                    detailRow("Status", member.verificationStatus ?? "unverified")
   270|                    detailRow("SMS Verified", member.smsVerified == true ? "Yes" : "No")
   271|                    detailRow("Email Verified", member.emailVerified == true ? "Yes" : "No")
   272|                }
   273|                Section("Interest") {
   274|                    detailRow("Investor Interest", member.investorInterest ?? "—")
   275|                    detailRow("Preferred Zipcode", member.preferredZipcode ?? "—")
   276|                    detailRow("Budget Range", member.budgetRange ?? "—")
   277|                }
   278|                Section("Timestamps") {
   279|                    detailRow("Registered", member.createdDate?.formatted(date: .abbreviated, time: .shortened) ?? member.createdAt ?? "—")
   280|                    detailRow("Updated", member.updatedAt ?? "—")
   281|                }
   282|            }
   283|            .listStyle(.insetGrouped)
   284|            .scrollContentBackground(.hidden)
   285|            .background(Color.ivxBackground)
   286|            .navigationTitle(member.displayName)
   287|            .navigationBarTitleDisplayMode(.inline)
   288|        }
   289|    }
   290|
   291|    private func detailRow(_ label: String, _ value: String, copyable: Bool = false) -> some View {
   292|        HStack(alignment: .top) {
   293|            Text(label)
   294|                .font(.caption)
   295|                .foregroundStyle(Color.ivxTextSecondary)
   296|                .frame(width: 110, alignment: .leading)
   297|            Text(value)
   298|                .font(.caption)
   299|                .fontWeight(.medium)
   300|                .textSelection(.enabled)
   301|            Spacer()
   302|            if copyable {
   303|                Button {
   304|                    UIPasteboard.general.string = value
   305|                    copiedField = label
   306|                } label: {
   307|                    Image(systemName: copiedField == label ? "checkmark" : "doc.on.doc")
   308|                        .font(.caption)
   309|                        .foregroundStyle(copiedField == label ? Color.ivxGreen : Color.ivxGold)
   310|                }
   311|                .buttonStyle(.borderless)
   312|            }
   313|        }
   314|        .listRowBackground(Color.ivxCard)
   315|    }
   316|}
